    for depth in range(1, hops + 1):
        next_frontier: set[str] = set()
        for n in frontier:
            for _, v in graph.out_edges(n):
                out.append({"node_id": v, "depth": depth})
                next_frontier.add(v)
        frontier = next_frontier
        if not frontier:
            break
    return out

